mapper.select:
SELECT s.storeName AS groupName, IFNULL(SUM(a.lesson_count), 0) AS finishLessons, ROUND(IFNULL(SUM(), 0), 2) AS income, ROUND(IFNULL(SUM(), 0), 2) AS cost, ROUND(IFNULL(SUM(), 0) - IFNULL(SUM(), 0), 2) AS grossProfit, CASE WHEN IFNULL(SUM(), 0) = 0 THEN 0 ELSE ROUND( (IFNULL(SUM(), 0) - IFNULL(SUM(), 0)) / SUM() * 100, 2) END AS grossRate FROM pt_private_appointment a JOIN pt_private_order o ON o.id = a.order_id LEFT JOIN pt_coach c ON c.id = a.coach_id AND c.deleted = 0 LEFT JOIN store s ON s.storeId = a.store_id
GROUP BY a.store_id, s.storeName ORDER BY income DESC
LIMIT #{offset}, #{limit}

SELECT c.coach_name AS groupName, MAX(s.storeName) AS coachStoreName, IFNULL(SUM(a.lesson_count), 0) AS finishLessons, ROUND(IFNULL(SUM(), 0), 2) AS income, ROUND(IFNULL(SUM(), 0), 2) AS cost, ROUND(IFNULL(SUM(), 0) - IFNULL(SUM(), 0), 2) AS grossProfit, CASE WHEN IFNULL(SUM(), 0) = 0 THEN 0 ELSE ROUND( (IFNULL(SUM(), 0) - IFNULL(SUM(), 0)) / SUM() * 100, 2) END AS grossRate FROM pt_private_appointment a JOIN pt_private_order o ON o.id = a.order_id LEFT JOIN pt_coach c ON c.id = a.coach_id AND c.deleted = 0 LEFT JOIN store s ON s.storeId = a.store_id
GROUP BY a.coach_id, c.coach_name ORDER BY income DESC
LIMIT #{offset}, #{limit}

SELECT o.product_name AS groupName, IFNULL(SUM(a.lesson_count), 0) AS finishLessons, ROUND(IFNULL(SUM(), 0), 2) AS income, ROUND(IFNULL(SUM(), 0), 2) AS cost, ROUND(IFNULL(SUM(), 0) - IFNULL(SUM(), 0), 2) AS grossProfit, CASE WHEN IFNULL(SUM(), 0) = 0 THEN 0 ELSE ROUND( (IFNULL(SUM(), 0) - IFNULL(SUM(), 0)) / SUM() * 100, 2) END AS grossRate FROM pt_private_appointment a JOIN pt_private_order o ON o.id = a.order_id LEFT JOIN pt_coach c ON c.id = a.coach_id AND c.deleted = 0
GROUP BY a.product_id, o.product_name ORDER BY income DESC
LIMIT #{offset}, #{limit}

SELECT DATE_FORMAT(a.finish_at, '%Y-%m-%d') AS finishDate, s.storeName AS storeName, c.coach_name AS coachName, o.product_name AS productName, IFNULL(o.member_name, o.member_mobile) AS memberInfo, o.order_no AS orderNo, o.lesson_count AS totalLessons, a.lesson_count AS finishLessons, ROUND(, 2) AS unitIncome, ROUND(, 2) AS unitCost, ROUND( - , 2) AS unitGross FROM pt_private_appointment a JOIN pt_private_order o ON o.id = a.order_id LEFT JOIN pt_coach c ON c.id = a.coach_id AND c.deleted = 0 LEFT JOIN store s ON s.storeId = a.store_id
ORDER BY a.finish_at DESC, a.id DESC
LIMIT #{offset}, #{limit}

SELECT DATE_FORMAT(a.finish_at, '%Y-%m-%d') AS finishDate, o.order_no AS orderNo, o.product_name AS productName, a.store_id AS storeId, a.coach_id AS coachId, CASE WHEN s.storeId IS NULL THEN '完成记录缺少门店' WHEN c.id IS NULL THEN '完成记录缺少教练' WHEN o.lesson_count <= 0 THEN '订单总课时非法(无法折算收入)' WHEN fr.id IS NULL THEN '教练课时费未配置(成本按0)' END AS abnormalReason FROM pt_private_appointment a JOIN pt_private_order o ON o.id = a.order_id LEFT JOIN pt_coach c ON c.id = a.coach_id AND c.deleted = 0 LEFT JOIN store s ON s.storeId = a.store_id
ORDER BY a.finish_at DESC, a.id DESC
LIMIT #{offset}, #{limit}
